css:
.loader {
  color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: #67e8f9;
  --loader-bg: #ffffff;
height: 15px;
aspect-ratio: 5;
background: radial-gradient(closest-side at 37.5% 50%,currentColor 94%,#0000) 0/calc(80%/3) 100%;
animation: l47 .75s infinite;
}
@keyframes l47 {
100% {background-position: 36.36%}
}
